const input = $input.first().json || {};
const trigger = $node['Telegram Trigger'] ? ($node['Telegram Trigger'].json || {}) : {};
const message = trigger.message || null;
const callbackQuery = trigger.callback_query || null;
const srcMessage = callbackQuery ? (callbackQuery.message || {}) : (message || {});
const from = callbackQuery ? (callbackQuery.from || {}) : ((message && message.from) || {});
const chat = srcMessage.chat || ((message && message.chat) || {});
const chatId = chat.id ? String(chat.id) : '';
const messageId = srcMessage.message_id;
const callbackId = callbackQuery ? callbackQuery.id : null;
const text = String((message && message.text) || '').trim();
const callbackData = String((callbackQuery && callbackQuery.data) || '').trim();
const command = callbackData || text || '/start';

const SUPABASE_URL = String(input.supabaseUrl || '').trim();
const SUPABASE_SERVICE_ROLE_KEY = String(input.supabaseServiceRoleKey || '').trim();
const TELEGRAM_BOT_TOKEN = String(input.telegramBotToken || '').trim();
const INITIAL_ADMIN_IDS = new Set(String(input.initialBotAdminTelegramUserIds || '').split(',').map(v => v.trim()).filter(Boolean));
const PUBLIC_BASE_URL = String(input.publicBaseUrl || 'https://cargadores-aspe.onlineexpansions.com').replace(/\/+$/, '');

const STATIC_STATION_COORDS = {
  ESIBE22E0001001: { lat: 38.341118679046346, lon: -0.7654778230267333 },
  ESIBE22E0001002: { lat: 38.3476704, lon: -0.7691027 },
  ESIBE22E0001003: { lat: 38.3498799, lon: -0.7649660 },
  ESIBE22E0001004: { lat: 38.3430059, lon: -0.7610202 },
  ESIBE22E0001005: { lat: 38.3385331, lon: -0.7766776 },
  'IBERDROLA-5629': { lat: 38.3810859, lon: -0.7308562 },
  ESIBE22E0005629: { lat: 38.3810859, lon: -0.7308562 }
};

if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY || !TELEGRAM_BOT_TOKEN) throw new Error('Faltan variables en Configuracion');
if (!chatId) return [{ json: { ok: true, ignored: true, reason: 'Sin chatId' } }];

function supabaseHeaders(prefer) {
  const h = { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' };
  if (prefer) h.Prefer = prefer;
  return h;
}

async function requestText(url, options) {
  if (typeof fetch === 'function') {
    const r = await fetch(url, options);
    const b = await r.text();
    return { ok: r.ok, status: r.status, body: b };
  }
  const helper = this && this.helpers && this.helpers.httpRequest;
  if (typeof helper !== 'function') throw new Error('fetch no disponible');
  const r = await helper({ url: url, method: options.method || 'GET', headers: options.headers, body: options.body, json: false, returnFullResponse: true, ignoreHttpStatusErrors: true });
  return { ok: r.statusCode >= 200 && r.statusCode < 300, status: r.statusCode, body: typeof r.body === 'string' ? r.body : JSON.stringify(r.body || '') };
}

async function supabaseGet(path) {
  const r = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'GET', headers: supabaseHeaders() });
  if (!r.ok) throw new Error('Supabase GET fallo: ' + path + ' -> ' + r.status + ' ' + r.body);
  return r.body ? JSON.parse(r.body) : [];
}

async function supabasePost(path, payload, prefer) {
  const r = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'POST', headers: supabaseHeaders(prefer), body: JSON.stringify(payload) });
  if (!r.ok) throw new Error('Supabase POST fallo: ' + path + ' -> ' + r.status + ' ' + r.body);
  return r.body ? JSON.parse(r.body) : [];
}

async function supabasePatch(path, payload, prefer) {
  const r = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'PATCH', headers: supabaseHeaders(prefer), body: JSON.stringify(payload) });
  if (!r.ok) throw new Error('Supabase PATCH fallo: ' + path + ' -> ' + r.status + ' ' + r.body);
  return r.body ? JSON.parse(r.body) : [];
}

async function telegramApi(method, payload) {
  const r = await requestText.call(this, 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/' + method, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload || {}) });
  if (!r.ok) throw new Error('Telegram API fallo en ' + method + ': ' + r.status + ' ' + r.body);
  return r.body ? JSON.parse(r.body) : {};
}

function kb(rows) { return { inline_keyboard: rows }; }

async function sendOrEdit(textOut, keyboard) {
  if (callbackQuery && messageId) {
    try {
      return await telegramApi.call(this, 'editMessageText', { chat_id: chatId, message_id: messageId, text: textOut, disable_web_page_preview: true, reply_markup: keyboard });
    } catch (e) {}
  }
  return await telegramApi.call(this, 'sendMessage', { chat_id: chatId, text: textOut, disable_web_page_preview: true, reply_markup: keyboard });
}

async function answer(textOut, alert) {
  if (!callbackId) return;
  try {
    await telegramApi.call(this, 'answerCallbackQuery', { callback_query_id: callbackId, text: textOut || '', show_alert: Boolean(alert) });
  } catch (e) {
    const msg = String((e && e.message) || e || '');
    if (msg.indexOf('query is too old and response timeout expired or query ID is invalid') !== -1) return;
    throw e;
  }
}

async function upsertUser() {
  const tgId = from.id ? String(from.id) : '';
  const tgUser = from.username ? String(from.username) : null;
  const existingRows = await supabaseGet.call(this, 'telegram_users?select=id,telegram_user_id,telegram_username,is_premium,is_bot_admin,is_blocked,blocked_until,anti_bot_strikes,command_window_start,command_window_count,last_command_at,is_active&telegram_user_id=eq.' + encodeURIComponent(tgId) + '&limit=1');
  const existing = Array.isArray(existingRows) && existingRows.length ? existingRows[0] : null;
  const isBotAdmin = Boolean((existing && existing.is_bot_admin) || INITIAL_ADMIN_IDS.has(tgId));
  const isPremium = Boolean(existing && existing.is_premium);
  const rows = await supabasePost.call(this, 'telegram_users?on_conflict=telegram_user_id', {
    telegram_user_id: tgId,
    telegram_chat_id: chatId,
    telegram_username: tgUser,
    is_premium: isPremium,
    is_bot_admin: isBotAdmin,
    is_blocked: Boolean(existing && existing.is_blocked),
    blocked_until: existing ? (existing.blocked_until || null) : null,
    anti_bot_strikes: Number(existing && existing.anti_bot_strikes || 0),
    command_window_start: existing ? (existing.command_window_start || null) : null,
    command_window_count: Number(existing && existing.command_window_count || 0),
    last_command_at: existing ? (existing.last_command_at || null) : null,
    is_active: true,
    last_interaction_at: new Date().toISOString()
  }, 'resolution=merge-duplicates,return=representation');
  return Array.isArray(rows) && rows.length ? rows[0] : null;
}

async function getStations() {
  return await supabaseGet.call(this, 'charger_current_status?select=station_id,location_name,is_available,available_connectors,total_connectors&order=location_name.asc');
}

async function getStation(stationId) {
  const rows = await supabaseGet.call(this, 'charger_current_status?select=station_id,location_name,is_available,available_connectors,total_connectors&station_id=eq.' + encodeURIComponent(stationId) + '&limit=1');
  return rows.length ? rows[0] : null;
}

async function getStationCoords(stationId) {
  try {
    const rows = await supabaseGet.call(this, 'charger_current_status?select=station_id,latitude,longitude&station_id=eq.' + encodeURIComponent(stationId) + '&limit=1');
    if (rows.length) {
      const r = rows[0] || {};
      if (Number.isFinite(Number(r.latitude)) && Number.isFinite(Number(r.longitude))) {
        return { lat: Number(r.latitude), lon: Number(r.longitude) };
      }
    }
  } catch (e) {}
  try {
    const rows = await supabaseGet.call(this, 'charger_current_status?select=station_id,lat,lng&station_id=eq.' + encodeURIComponent(stationId) + '&limit=1');
    if (rows.length) {
      const r = rows[0] || {};
      if (Number.isFinite(Number(r.lat)) && Number.isFinite(Number(r.lng))) {
        return { lat: Number(r.lat), lon: Number(r.lng) };
      }
    }
  } catch (e) {}
  const staticCoords = STATIC_STATION_COORDS[String(stationId || '')];
  if (staticCoords && Number.isFinite(Number(staticCoords.lat)) && Number.isFinite(Number(staticCoords.lon))) {
    return { lat: Number(staticCoords.lat), lon: Number(staticCoords.lon) };
  }
  return null;
}

async function getSubs(userId) {
  const nowIso = encodeURIComponent(new Date().toISOString());
  return await supabaseGet.call(this, 'notification_subscriptions?select=id,station_id,notify_mode,zone,expires_at&user_id=eq.' + encodeURIComponent(userId) + '&active=eq.true&expires_at=gt.' + nowIso + '&order=created_at.desc');
}

async function getUsers() {
  return await supabaseGet.call(this, 'telegram_users?select=id,telegram_user_id,telegram_username,is_premium,is_bot_admin,is_blocked,blocked_until&order=telegram_username.asc.nullslast,telegram_user_id.asc&limit=40');
}

function userLabel(u) { return u.telegram_username ? ('@' + u.telegram_username) : ('ID ' + u.telegram_user_id); }

function parseCommand(raw) {
  const src = String(raw || '').trim();
  return { raw: src, parts: src.split(':') };
}

function isHumanVerified(user) {
  const markerMs = user && user.command_window_start ? new Date(user.command_window_start).getTime() : NaN;
  return Number.isFinite(markerMs) && markerMs === 0;
}

function buildHumanChallenge(tgUserId) {
  const seed = Math.abs(Number(String(tgUserId || '').slice(-6)) || 1) + (Date.now() % 997);
  const a = 2 + (seed % 8);
  const b = 1 + ((seed * 3) % 9);
  const ok = a + b;
  const wrong1 = ok + ((seed % 3) + 1);
  const wrong2 = Math.max(0, ok - ((seed % 2) + 1));
  const opts = [ok, wrong1, wrong2].sort(() => Math.random() - 0.5);
  const rows = opts.map(v => [{ text: String(v), callback_data: 'human:sum:' + a + ':' + b + ':' + v }]);
  rows.push([{ text: 'Cambiar reto', callback_data: 'human:sum:' + a + ':' + b + ':retry' }]);
  return { text: 'Verificacion humana\n\nCuanto es ' + a + ' + ' + b + '?', keyboard: kb(rows) };
}

async function sendHumanChallenge(reasonText) {
  const ch = buildHumanChallenge(from && from.id ? String(from.id) : '0');
  const fullText = reasonText ? (reasonText + '\n\n' + ch.text) : ch.text;
  await sendOrEdit.call(this, fullText, ch.keyboard);
}

async function verifyHumanAndPersist(user, cmd) {
  if (!cmd || cmd.parts[0] !== 'human' || cmd.parts[1] !== 'sum') return false;
  const a = Number(cmd.parts[2]);
  const b = Number(cmd.parts[3]);
  const rToken = String(cmd.parts[4] || '');
  if (!Number.isFinite(a) || !Number.isFinite(b) || rToken === 'retry') return false;
  const r = Number(rToken);
  if (!Number.isFinite(r) || r !== (a + b)) return false;

  const nowIso = new Date().toISOString();
  await supabasePatch.call(this, 'telegram_users?id=eq.' + encodeURIComponent(user.id), {
    anti_bot_strikes: 0,
    is_blocked: false,
    blocked_until: null,
    command_window_start: '1970-01-01T00:00:00.000Z',
    command_window_count: 0,
    last_command_at: nowIso,
    last_interaction_at: nowIso
  }, 'return=minimal');
  return true;
}


function modeLabel(notifyMode, zone) {
  if (String(zone || '').indexOf('maxlimit:') === 0) {
    const n = String(zone).split(':')[1] || '?';
    return 'max ' + n + ' avisos';
  }
  return notifyMode === 'repeat' ? 'continuo' : 'primer aviso';
}

function durationLabel(hours) {
  return String(hours) + 'h';
}

function remainingLabel(expiresAt) {
  const ms = new Date(expiresAt || '').getTime() - Date.now();
  if (!Number.isFinite(ms) || ms <= 0) return 'expirada';
  const totalMin = Math.ceil(ms / 60000);
  const h = Math.floor(totalMin / 60);
  const m = totalMin % 60;
  if (h > 0 && m > 0) return 'durante las proximas ' + h + 'h ' + m + 'min';
  if (h > 0) return 'durante las proximas ' + h + 'h';
  return 'durante los proximos ' + m + 'min';
}

async function menu(user) {
  const premiumTxt = user.is_premium ? 'Premium: activado' : 'Premium: normal';
  const adminTxt = user.is_bot_admin ? '\nRol: administrador del bot' : '';
  const rows = [
    [{ text: 'Suscribirme a un cargador', callback_data: 'sub:list' }],
    [{ text: 'Mis notificaciones', callback_data: 'mysubs:list' }],
    [{ text: 'Ver estado actual', callback_data: 'status:list' }]
  ];
  if (user.is_bot_admin) rows.push([{ text: 'Gestionar premium', callback_data: 'premium:list' }]);
  await sendOrEdit.call(this, 'Panel del bot de cargadores de Aspe\n\n' + premiumTxt + adminTxt, kb(rows));
}

async function statusList() {
  const stations = await getStations.call(this);
  if (!stations.length) return await sendOrEdit.call(this, 'No hay estado disponible.', kb([[{ text: 'Menú', callback_data: 'menu:main' }]]));
  const rows = stations.map(s => [{ text: (s.is_available ? '🟢 ' : '🔴 ') + s.location_name.slice(0, 48), callback_data: 'st:d:' + s.station_id }]);
  rows.push([{ text: 'Suscribirme', callback_data: 'sub:list' }]);
  rows.push([{ text: 'Menú', callback_data: 'menu:main' }]);
  await sendOrEdit.call(this, 'Estado actual: pulsa un cargador para ver detalle y actualizar.', kb(rows));
}

async function statusDetail(stationId) {
  const station = await getStation.call(this, stationId);
  if (!station) return await sendOrEdit.call(this, 'No he encontrado ese cargador.', kb([[{ text: 'Estado', callback_data: 'status:list' }], [{ text: 'Menú', callback_data: 'menu:main' }]]));
  const avail = station.is_available ? 'Libre' : 'Ocupado';
  const c = station.available_connectors == null || station.total_connectors == null ? '' : (' (' + station.available_connectors + '/' + station.total_connectors + ')');
  const txt = station.location_name + '\nEstado: ' + avail + c + '\n\nPuedes actualizar, abrir mapa o crear alerta.';
  await sendOrEdit.call(this, txt, kb([
    [{ text: 'Actualizar', callback_data: 'st:r:' + station.station_id }],
    [{ text: 'Mapa', callback_data: 'st:m:' + station.station_id }],
    [{ text: 'Crear alerta', callback_data: 'sub:s:' + station.station_id }],
    [{ text: 'Volver al estado', callback_data: 'status:list' }],
    [{ text: 'Menú', callback_data: 'menu:main' }]
  ]));
}

async function sendStationLocation(stationId) {
  const station = await getStation.call(this, stationId);
  if (!station) return await sendOrEdit.call(this, 'No he encontrado ese cargador.', kb([[{ text: 'Estado', callback_data: 'status:list' }], [{ text: 'Menú', callback_data: 'menu:main' }]]));

  const coords = await getStationCoords.call(this, stationId);
  if (coords) {
    await telegramApi.call(this, 'sendLocation', { chat_id: chatId, latitude: coords.lat, longitude: coords.lon });
    await telegramApi.call(this, 'sendMessage', { chat_id: chatId, text: 'Identificador del cargador: ' + station.station_id + '\nUbicacion: ' + station.location_name, disable_web_page_preview: true });
    await answer.call(this, 'Ubicacion enviada', false);
  } else {
    const mapUrl = 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(station.location_name + ', Aspe');
    await telegramApi.call(this, 'sendMessage', { chat_id: chatId, text: 'No tengo coordenadas exactas. Mapa aproximado:\n' + mapUrl, disable_web_page_preview: false });
  }

  await statusDetail.call(this, stationId);
}

async function subscribeList() {
  const stations = await getStations.call(this);
  if (!stations.length) return await sendOrEdit.call(this, 'No encuentro cargadores ahora mismo.', kb([[{ text: 'Menú', callback_data: 'menu:main' }]]));
  const rows = stations.map(s => [{ text: s.location_name + ' · ' + (s.is_available ? 'Libre' : 'Ocupado'), callback_data: 'sub:s:' + s.station_id }]);
  rows.push([{ text: 'Menú', callback_data: 'menu:main' }]);
  await sendOrEdit.call(this, 'Elige un cargador para configurar tu alerta:', kb(rows));
}

async function askDuration(stationId) {
  await sendOrEdit.call(this, 'Duracion de la alerta:', kb([
    [{ text: '1h', callback_data: 'sub:h:' + stationId + ':1' }, { text: '3h', callback_data: 'sub:h:' + stationId + ':3' }],
    [{ text: '8h', callback_data: 'sub:h:' + stationId + ':8' }, { text: '24h', callback_data: 'sub:h:' + stationId + ':24' }],
    [{ text: '72h', callback_data: 'sub:h:' + stationId + ':72' }],
    [{ text: 'Volver', callback_data: 'sub:list' }],
    [{ text: 'Menú', callback_data: 'menu:main' }]
  ]));
}

async function askMode(stationId, hoursRaw) {
  const hours = Math.max(1, Math.min(168, Number(hoursRaw) || 24));
  await sendOrEdit.call(this, 'Modo de notificacion para ' + durationLabel(hours) + ':', kb([
    [{ text: 'Primer aviso', callback_data: 'sub:c:' + stationId + ':' + hours + ':first_only' }],
    [{ text: 'Continuo', callback_data: 'sub:c:' + stationId + ':' + hours + ':repeat' }],
    [{ text: 'Parar en 1 aviso', callback_data: 'sub:c:' + stationId + ':' + hours + ':max1' }],
    [{ text: 'Parar en 3 avisos', callback_data: 'sub:c:' + stationId + ':' + hours + ':max3' }],
    [{ text: 'Parar en 5 avisos', callback_data: 'sub:c:' + stationId + ':' + hours + ':max5' }],
    [{ text: 'Volver', callback_data: 'sub:s:' + stationId }],
    [{ text: 'Menú', callback_data: 'menu:main' }]
  ]));
}

function modeFromToken(token) {
  const t = String(token || '').trim();
  if (t === 'first_only' || t === 'repeat') return { notifyMode: t, zone: null, label: modeLabel(t, null) };
  if (t.indexOf('max') === 0) {
    const n = Number(t.slice(3));
    const max = Number.isFinite(n) && n > 0 ? Math.floor(n) : 1;
    return { notifyMode: 'repeat', zone: 'maxlimit:' + max, label: 'max ' + max + ' avisos' };
  }
  return { notifyMode: 'first_only', zone: null, label: modeLabel('first_only', null) };
}

async function createSubscription(user, stationId, hoursRaw, modeToken) {
  const hours = Math.max(1, Math.min(168, Number(hoursRaw) || 24));
  const chosen = modeFromToken(modeToken);
  const nowIsoRaw = new Date().toISOString();
  const nowIso = encodeURIComponent(nowIsoRaw);
  await supabasePatch.call(this, 'notification_subscriptions?user_id=eq.' + encodeURIComponent(user.id) + '&station_id=eq.' + encodeURIComponent(stationId) + '&active=eq.true&expires_at=lte.' + nowIso, { active: false }, 'return=minimal');
  const exists = await supabaseGet.call(this, 'notification_subscriptions?select=id&user_id=eq.' + encodeURIComponent(user.id) + '&station_id=eq.' + encodeURIComponent(stationId) + '&active=eq.true&expires_at=gt.' + nowIso + '&limit=1');
  if (exists.length) return await sendOrEdit.call(this, 'Ya tienes una alerta activa para ese cargador.', kb([[{ text: 'Mis notificaciones', callback_data: 'mysubs:list' }], [{ text: 'Menú', callback_data: 'menu:main' }]]));

  const expiresAt = new Date(Date.now() + hours * 60 * 60 * 1000).toISOString();
  await supabasePost.call(this, 'notification_subscriptions', {
    user_id: user.id,
    station_id: stationId,
    notify_mode: chosen.notifyMode,
    zone: chosen.zone,
    cooldown_minutes: 30,
    expires_at: expiresAt,
    active: true
  }, 'return=minimal');

  const stationNow = await getStation.call(this, stationId);
  if (stationNow && stationNow.is_available) {
    await telegramApi.call(this, 'sendMessage', { chat_id: chatId, text: '⚡ Cargador libre ahora\n' + stationNow.location_name + '\n\nVer estado: ' + PUBLIC_BASE_URL + '/charger/' + encodeURIComponent(stationId), disable_web_page_preview: true });
  }

  await sendOrEdit.call(this, 'Alerta creada: ' + stationId + '\nDuracion: ' + durationLabel(hours) + '\nModo: ' + chosen.label + (stationNow && stationNow.is_available ? '\n\n⚡ El cargador estaba libre, ya te he avisado.' : ''), kb([
    [{ text: 'Mis notificaciones', callback_data: 'mysubs:list' }],
    [{ text: 'Crear otra', callback_data: 'sub:list' }],
    [{ text: 'Menú', callback_data: 'menu:main' }]
  ]));
}

async function mySubs(user) {
  const subs = await getSubs.call(this, user.id);
  if (!subs.length) return await sendOrEdit.call(this, 'No tienes alertas activas.', kb([[{ text: 'Crear alerta', callback_data: 'sub:list' }], [{ text: 'Menú', callback_data: 'menu:main' }]]));
  const stations = await getStations.call(this);
  const byId = new Map(stations.map(s => [s.station_id, s.location_name]));
  const lines = ['Tus notificaciones activas:'];
  const rows = [];
  for (const sub of subs) {
    const label = byId.get(sub.station_id) || sub.station_id;
    lines.push('• ' + label + ' · ' + modeLabel(sub.notify_mode, sub.zone) + ' · ' + remainingLabel(sub.expires_at));
    rows.push([{ text: 'Detalle ' + label.slice(0, 24), callback_data: 'st:d:' + sub.station_id }]);
    rows.push([{ text: 'Eliminar ' + label.slice(0, 24), callback_data: 'sub:del:' + sub.id }]);
  }
  rows.push([{ text: 'Menú', callback_data: 'menu:main' }]);
  await sendOrEdit.call(this, lines.join('\n'), kb(rows));
}

async function removeSub(user, subId) {
  const rows = await supabasePatch.call(this, 'notification_subscriptions?id=eq.' + encodeURIComponent(subId) + '&user_id=eq.' + encodeURIComponent(user.id), { active: false }, 'return=representation');
  if (!rows.length) return await sendOrEdit.call(this, 'No he podido eliminar esa alerta.', kb([[{ text: 'Mis notificaciones', callback_data: 'mysubs:list' }], [{ text: 'Menú', callback_data: 'menu:main' }]]));
  await sendOrEdit.call(this, 'Alerta eliminada.', kb([[{ text: 'Mis notificaciones', callback_data: 'mysubs:list' }], [{ text: 'Menú', callback_data: 'menu:main' }]]));
}

async function premiumList(user) {
  if (!user.is_bot_admin) {
    await answer.call(this, 'Solo un administrador puede gestionar premium.', true);
    return await menu.call(this, user);
  }
  const users = await getUsers.call(this);
  const lines = ['Gestionar premium:'];
  const rows = [];
  for (const u of users) {
    const marker = u.is_premium ? 'SI' : 'NO';
    const blocked = u.is_blocked ? ' · bloqueado' : '';
    lines.push(marker + ' ' + userLabel(u) + (u.is_bot_admin ? ' · admin' : '') + blocked);
    rows.push([{ text: (u.is_premium ? 'Quitar premium a ' : 'Dar premium a ') + userLabel(u).slice(0, 18), callback_data: 'premium:toggle:' + u.id }]);
  }
  rows.push([{ text: 'Menú', callback_data: 'menu:main' }]);
  await sendOrEdit.call(this, lines.join('\n'), kb(rows));
}

async function premiumToggle(actor, targetId) {
  if (!actor.is_bot_admin) {
    await answer.call(this, 'Solo un administrador puede gestionar premium.', true);
    return await menu.call(this, actor);
  }
  const rows = await supabaseGet.call(this, 'telegram_users?select=id,is_premium&id=eq.' + encodeURIComponent(targetId) + '&limit=1');
  const target = rows.length ? rows[0] : null;
  if (!target) return await sendOrEdit.call(this, 'No he encontrado ese usuario.', kb([[{ text: 'Gestionar premium', callback_data: 'premium:list' }], [{ text: 'Menú', callback_data: 'menu:main' }]]));
  await supabasePatch.call(this, 'telegram_users?id=eq.' + encodeURIComponent(target.id), { is_premium: !target.is_premium }, 'return=minimal');
  await premiumList.call(this, actor);
}

const user = await upsertUser.call(this);
if (!user) throw new Error('No se pudo crear o recuperar el usuario');

let cmd = parseCommand(command);
if (!isHumanVerified(user)) {
  if (cmd.parts[0] === 'human' && cmd.parts[1] === 'sum') {
    const ok = await verifyHumanAndPersist.call(this, user, cmd);
    if (!ok) {
      if (callbackId) await answer.call(this, 'Respuesta incorrecta', true);
      await sendHumanChallenge.call(this, 'Respuesta incorrecta. Intentalo de nuevo.');
      return [{ json: { ok: true, humanVerified: false, handledCommand: command, chatId: chatId, telegramUserId: from.id ? String(from.id) : null } }];
    }
    if (callbackId) await answer.call(this, 'Verificacion correcta', false);
    user.anti_bot_strikes = 0;
    user.command_window_start = '1970-01-01T00:00:00.000Z';
    user.last_command_at = new Date().toISOString();
    cmd = parseCommand('/menu');
  } else {
    await sendHumanChallenge.call(this, 'Antes de usar el bot, resuelve esta suma.');
    return [{ json: { ok: true, humanVerified: false, handledCommand: command, chatId: chatId, telegramUserId: from.id ? String(from.id) : null } }];
  }
}

const currentUser = user;
if (callbackId) await answer.call(this, 'Procesando', false);

if (cmd.raw === '/start' || cmd.raw === '/menu' || cmd.raw === 'menu:main') {
  await menu.call(this, currentUser);
} else if (cmd.raw === 'status:list') {
  await statusList.call(this);
} else if (cmd.parts[0] === 'st' && cmd.parts[1] === 'd' && cmd.parts[2]) {
  await statusDetail.call(this, cmd.parts[2]);
} else if (cmd.parts[0] === 'st' && cmd.parts[1] === 'r' && cmd.parts[2]) {
  await statusDetail.call(this, cmd.parts[2]);
} else if (cmd.parts[0] === 'st' && cmd.parts[1] === 'm' && cmd.parts[2]) {
  await sendStationLocation.call(this, cmd.parts[2]);
} else if (cmd.raw === 'sub:list' || cmd.raw === 'subscribe:list') {
  await subscribeList.call(this);
} else if (cmd.parts[0] === 'sub' && cmd.parts[1] === 's' && cmd.parts[2]) {
  await askDuration.call(this, cmd.parts[2]);
} else if (cmd.parts[0] === 'sub' && cmd.parts[1] === 'h' && cmd.parts[2] && cmd.parts[3]) {
  await askMode.call(this, cmd.parts[2], cmd.parts[3]);
} else if (cmd.parts[0] === 'sub' && cmd.parts[1] === 'c' && cmd.parts[2] && cmd.parts[3] && cmd.parts[4]) {
  await createSubscription.call(this, currentUser, cmd.parts[2], cmd.parts[3], cmd.parts[4]);
} else if (cmd.raw === 'mysubs:list') {
  await mySubs.call(this, currentUser);
} else if (cmd.parts[0] === 'sub' && cmd.parts[1] === 'del' && cmd.parts[2]) {
  await removeSub.call(this, currentUser, cmd.parts[2]);
} else if (cmd.raw === 'premium:list') {
  await premiumList.call(this, currentUser);
} else if (cmd.parts[0] === 'premium' && cmd.parts[1] === 'toggle' && cmd.parts[2]) {
  await premiumToggle.call(this, currentUser, cmd.parts[2]);
} else {
  await menu.call(this, currentUser);
}

return [{ json: { ok: true, handledCommand: command, chatId: chatId, telegramUserId: from.id ? String(from.id) : null } }];

